def minimumScore(self, s: str, t: str) -> int:
    n = len(s)
    m = len(t)
    dp = [0] * (m + 1)
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if s[i - 1] == t[j - 1]:
                dp[j] = min(dp[j], dp[j - 1] + 1)
            else:
                dp[j] = max(dp[j], dp[j - 1])
    return dp[m]

